sys_script.script:
(function executeRule(current, previous) {
    var platform = current.getValue('platform');
    var scheduledTime = new GlideDateTime(current.getValue('scheduled_date_time'));

    gs.addInfoMessage("Running, checking date: " + scheduledTime.getDisplayValue());

    var conflicts = findConflicts(platform, scheduledTime, current.sys_id);

    if (conflicts.length > 0) {
        var message = "🚫 SCHEDULING CONFLICT!\n\n";
        message += "We're sorry, but the selected time conflicts with the following scheduled post(s):\n\n";

        conflicts.forEach(function(conflict) {
            message += "• " + conflict.description + " at " + conflict.time + "\n";
        });

        message += "\nPlease choose a time that is at least 1 hour apart from other posts.";

        gs.addErrorMessage(message);
        current.setAbortAction(true);
    } else {
        gs.addInfoMessage("✅ Amazing! No scheduling conflicts found. You're good to go!");
    }

    function findConflicts(platform, time, currentId) {
        var results = [];
        var gr = new GlideRecord('x_1667915_4dot_social_media_activity');
        gr.addQuery('platform', platform);
        gr.addQuery('sys_id', '!=', currentId);
        gr.addQuery('scheduled_date_time', '!=', '');
        gr.query();

        while (gr.next()) {
            var existingTimeVal = gr.getValue('scheduled_date_time');
            if (!existingTimeVal) continue;

            var existingTime = new GlideDateTime(existingTimeVal);
            var diffMinutes = Math.abs(existingTime.getNumericValue() - time.getNumericValue()) / 60000;

            gs.addInfoMessage("Checking conflict: Existing = " + existingTime.getDisplayValue() +
                " | New = " + time.getDisplayValue() +
                " | Diff = " + diffMinutes + " minutes");

            if (diffMinutes < 60) {
                gs.addInfoMessage("✅ Conflict found: " + gr.getDisplayValue('content_description') + " at " + existingTime.getDisplayValue());
                results.push({
                    description: gr.getDisplayValue('content_description'),
                    time: existingTime.getDisplayValue()
                });
            }
        }

        return results;
    }
})(current, previous);
